import os, struct, json, binascii, re
from pathlib import Path
from urllib.parse import parse_qsl

PCAP='/home/ctfplayer/ctf_files/cap.pcap'
OUTDIR=Path('/home/ctfplayer/ctf_files/extracted')
OUTDIR.mkdir(exist_ok=True)

BMP_SIGS=[b'PK\x03\x04',b'FLAG{',b'%PDF',b'GIF8',b'\x89PNG\r\n\x1a\n',b'7z\xbc\xaf\x27\x1c',b'Rar!\x1a\x07\x00',b'Rar!\x1a\x07\x01\x00',b'BM']


def read_pcap(path):
    with open(path,'rb') as f:
        gh=f.read(24)
        if gh[:4]==b'\xd4\xc3\xb2\xa1': endian='<'
        elif gh[:4]==b'\xa1\xb2\xc3\xd4': endian='>'
        else: raise ValueError('bad pcap')
        idx=0
        while True:
            ph=f.read(16)
            if len(ph)<16: break
            ts_sec,ts_usec,incl,orig=struct.unpack(endian+'IIII',ph)
            data=f.read(incl); idx+=1
            yield idx, ts_sec + ts_usec/1e6, data

def iter_posts():
    for frame,ts,data in read_pcap(PCAP):
        if len(data)<54 or data[12:14]!=b'\x08\x00': continue
        ip=data[14:]
        if ip[9]!=6: continue
        ihl=(ip[0]&0xf)*4
        src='.'.join(map(str,ip[12:16])); dst='.'.join(map(str,ip[16:20]))
        tcp=ip[ihl:]
        sport,dport=struct.unpack('!HH',tcp[:4])
        doff=((tcp[12]>>4)&0xf)*4
        payload=tcp[doff:]
        if dst=='192.168.0.21' and dport==8080 and payload.startswith(b'POST '):
            yield frame, ts, src, sport, payload

def inspect_bmp(path):
    b=Path(path).read_bytes()
    info={'exists':True,'actual_size':len(b),'declared_size':None,'pixel_offset':None,'dib_header_size':None,'width':None,'height':None,'bpp':None,'compression':None,'trailing_len':0,'embedded':[],'strings':[],'notes':[]}
    if len(b)<14:
        info['notes'].append('too short for BMP header')
        return info
    if b[:2]!=b'BM':
        info['notes'].append('missing BM signature')
    if len(b)>=14:
        info['declared_size']=struct.unpack_from('<I',b,2)[0]
        info['pixel_offset']=struct.unpack_from('<I',b,10)[0]
    if len(b)>=54:
        info['dib_header_size']=struct.unpack_from('<I',b,14)[0]
        info['width']=struct.unpack_from('<I',b,18)[0]
        info['height']=struct.unpack_from('<I',b,22)[0]
        info['bpp']=struct.unpack_from('<H',b,28)[0]
        info['compression']=struct.unpack_from('<I',b,30)[0]
    if info['declared_size'] is not None and len(b)>info['declared_size']:
        info['trailing_len']=len(b)-info['declared_size']
        trail=b[info['declared_size']:]
        for sig in BMP_SIGS:
            pos=trail.find(sig)
            if pos!=-1:
                info['embedded'].append({'sig':sig.decode('latin1','replace'),'offset_in_trailing':pos})
        m=re.search(b'FLAG\{[^\}]{0,200}\}',trail)
        if m:
            info['embedded'].append({'flag':m.group().decode('latin1','replace')})
    m=re.search(b'FLAG\{[^\}]{0,200}\}',b)
    if m:
        info['embedded'].append({'flag_anywhere':m.group().decode('latin1','replace')})
    for needle in [b'PK\x03\x04',b'%PDF',b'\x89PNG\r\n\x1a\n',b'FLAG{']:
        pos=b.find(needle)
        if pos>0:
            info['embedded'].append({'sig_anywhere':needle.decode('latin1','replace'),'offset':pos})
    # ascii strings
    strs=re.findall(rb'[ -~]{6,}',b)
    info['strings']=[s.decode('latin1') for s in strs[:10]]
    return info

reqs=[]
for req_idx,(frame,ts,src,sport,payload) in enumerate(iter_posts(),1):
    if b'\r\n\r\n' not in payload:
        reqs.append({'req_idx':req_idx,'frame':frame,'ts':ts,'anomaly':'no header/body split'})
        continue
    hdr,body=payload.split(b'\r\n\r\n',1)
    header_lines=hdr.decode('latin1','replace').split('\r\n')
    headers={}
    for line in header_lines[1:]:
        if ':' in line:
            k,v=line.split(':',1); headers[k.strip().lower()]=v.strip()
    clen=int(headers.get('content-length','-1')) if headers.get('content-length','-1').isdigit() else None
    body_trim=body[:clen] if clen is not None and clen>=0 else body
    fields=parse_qsl(body_trim.decode('latin1','replace'), keep_blank_values=True)
    fdict={k:v for k,v in fields}
    x=fdict.get('x')
    n=fdict.get('n')
    rec={'req_idx':req_idx,'frame':frame,'ts':ts,'src_port':sport,'content_length':clen,'body_seen_len':len(body),'field_names':[k for k,v in fields],'len_n':len(n) if n is not None else None,'len_x':len(x) if x is not None else None,'has_x':x is not None,'anomalies':[]}
    if clen is not None and len(body)<clen: rec['anomalies'].append(f'truncated_body_seen_{len(body)}_lt_clen_{clen}')
    if clen is not None and len(body)>clen: rec['anomalies'].append(f'extra_bytes_after_body_{len(body)-clen}')
    if x is not None:
        try:
            xb=binascii.unhexlify(x)
            out=OUTDIR/f'req_{req_idx:03d}.bmp'
            out.write_bytes(xb)
            rec['bmp_file']=str(out)
            rec['bmp_size']=len(xb)
            rec['bmp_info']=inspect_bmp(out)
        except Exception as e:
            rec['anomalies'].append(f'malformed_hex_x:{e}')
    reqs.append(rec)

# stats/outliers
x_lens=[r['len_x'] for r in reqs if r.get('len_x') is not None]
uniq=sorted(set(x_lens))
from collections import Counter
cnt=Counter(x_lens)
summary={'total_posts':len(reqs),'x_length_counts':cnt,'first_x_req':next((r['req_idx'] for r in reqs if r['has_x']),None),'first_x_frame':next((r['frame'] for r in reqs if r['has_x']),None)}
Path('/home/ctfplayer/ctf_files/extracted/report.json').write_text(json.dumps({'summary':summary,'requests':reqs},indent=2))
print(json.dumps(summary,indent=2,default=str))
# print suspicious concise
for r in reqs:
    sus=[]
    if r['anomalies']: sus.append('anomaly')
    bi=r.get('bmp_info',{})
    if bi.get('trailing_len',0): sus.append(f"trailing={bi['trailing_len']}")
    if bi.get('embedded'): sus.append('embedded')
    if sus:
        print('SUS',r['req_idx'],'frame',r['frame'],'len_x',r['len_x'],sus, r.get('bmp_file',''))
        print('  bmp_info',bi)
PY

