import struct, socket, urllib.parse, os, json, binascii, re
PCAP='/home/ctfplayer/ctf_files/cap.pcap'
OUTDIR='/home/ctfplayer/ctf_files/extracted'
os.makedirs(OUTDIR, exist_ok=True)

def inet(b):
    return socket.inet_ntoa(b)

def parse_pcap(path):
    with open(path,'rb') as f:
        gh=f.read(24)
        if len(gh)<24: raise ValueError('short pcap')
        magic=gh[:4]
        if magic==b'\xd4\xc3\xb2\xa1': endian='<'
        elif magic==b'\xa1\xb2\xc3\xd4': endian='>'
        else: raise ValueError('bad magic')
        frames=[]
        idx=0
        while True:
            ph=f.read(16)
            if len(ph)<16: break
            ts_sec,ts_usec,incl,orig=struct.unpack(endian+'IIII',ph)
            data=f.read(incl)
            idx+=1
            frames.append((idx,ts_sec,ts_usec,data))
        return frames

def tcp_payload(frame):
    idx,ts_sec,ts_usec,data=frame
    if len(data)<14 or data[12:14]!=b'\x08\x00': return None
    ip=data[14:]
    if len(ip)<20 or ip[9]!=6: return None
    ihl=(ip[0]&0xf)*4
    if len(ip)<ihl+20: return None
    total=struct.unpack('!H',ip[2:4])[0]
    src=inet(ip[12:16]); dst=inet(ip[16:20])
    tcp=ip[ihl:total]
    sport,dport,seq,ack,off_flags=struct.unpack('!HHIIH',tcp[:14])
    doff=((off_flags>>12)&0xf)*4
    flags=off_flags & 0x1ff
    payload=tcp[doff:]
    return {'frame_idx':idx,'ts_sec':ts_sec,'ts_usec':ts_usec,'src':src,'dst':dst,'sport':sport,'dport':dport,'seq':seq,'ack':ack,'flags':flags,'payload':payload}

def inspect_bmp(path, raw):
    info={'path':path,'actual_size':len(raw),'is_bmp':False}
    if len(raw)>=2 and raw[:2]==b'BM':
        info['is_bmp']=True
        if len(raw)>=54:
            info['declared_size']=struct.unpack('<I',raw[2:6])[0]
            info['pixel_offset']=struct.unpack('<I',raw[10:14])[0]
            info['dib_size']=struct.unpack('<I',raw[14:18])[0]
            if len(raw)>=26:
                info['width']=struct.unpack('<I',raw[18:22])[0]
                info['height']=struct.unpack('<I',raw[22:26])[0]
            ds=info['declared_size']
            if ds < len(raw):
                info['trailing_bytes']=len(raw)-ds
                tail=raw[ds:ds+64]
                info['tail_preview_hex']=tail.hex()
                sigs=[]
                for sig,name in [(b'PK\x03\x04','zip'),(b'FLAG{','flag'),(b'\x89PNG\r\n\x1a\n','png'),(b'\xff\xd8\xff','jpeg'),(b'GIF87a','gif'),(b'GIF89a','gif'),(b'%PDF','pdf')]:
                    pos=raw.find(sig, ds)
                    if pos!=-1: sigs.append({'name':name,'offset':pos})
                info['embedded_sigs']=sigs
            elif ds > len(raw):
                info['size_mismatch']='declared_gt_actual'
            for sig,name in [(b'PK\x03\x04','zip'),(b'FLAG{','flag'),(b'\x89PNG\r\n\x1a\n','png'),(b'\xff\xd8\xff','jpeg'),(b'GIF87a','gif'),(b'GIF89a','gif'),(b'%PDF','pdf')]:
                pos=raw.find(sig)
                if pos!=-1:
                    info.setdefault('embedded_sigs_anywhere',[]).append({'name':name,'offset':pos})
    else:
        info['magic']=raw[:16].hex()
    m=re.search(b'FLAG\{[^}]{0,200}\}', raw)
    if m: info['flag_string']=m.group().decode('ascii','ignore')
    return info

frames=parse_pcap(PCAP)
streams={}
stream_meta={}
for fr in frames:
    t=tcp_payload(fr)
    if not t: continue
    if t['dst']=='192.168.0.21' and t['dport']==8080:
        key=(t['src'],t['sport'],t['dst'],t['dport'])
        streams.setdefault(key,[]).append(t)

requests=[]
req_idx=0
for key,pkts in streams.items():
    pkts.sort(key=lambda x:(x['seq'], x['frame_idx']))
    data=b''
    seen=[]
    next_seq=None
    for p in pkts:
        if not p['payload']: continue
        if next_seq is None:
            data+=p['payload']; seen.append((p['frame_idx'], len(p['payload']))); next_seq=p['seq']+len(p['payload'])
        else:
            if p['seq']<next_seq:
                overlap=next_seq-p['seq']
                if overlap < len(p['payload']):
                    data+=p['payload'][overlap:]; seen.append((p['frame_idx'], len(p['payload'])-overlap)); next_seq+=len(p['payload'])-overlap
            elif p['seq']==next_seq:
                data+=p['payload']; seen.append((p['frame_idx'], len(p['payload']))); next_seq+=len(p['payload'])
            else:
                data+=b''
    pos=0
    while True:
        hdr_end=data.find(b'\r\n\r\n', pos)
        if hdr_end==-1: break
        head=data[pos:hdr_end].decode('latin1','ignore')
        lines=head.split('\r\n')
        if not lines or not lines[0].startswith('POST '):
            pos=hdr_end+4
            continue
        headers={}
        for ln in lines[1:]:
            if ':' in ln:
                k,v=ln.split(':',1); headers[k.strip().lower()]=v.strip()
        cl=int(headers.get('content-length','0'))
        body_start=hdr_end+4
        body_end=body_start+cl
        if body_end>len(data):
            body=data[body_start:]
            anomaly='truncated_body'
        else:
            body=data[body_start:body_end]
            anomaly=''
        req_idx+=1
        fields=urllib.parse.parse_qs(body.decode('latin1','ignore'), keep_blank_values=True, strict_parsing=False)
        flat={k:v[0] if v else '' for k,v in fields.items()}
        rec={'req_idx':req_idx,'stream':key,'frame_idx':seen[0][0] if seen else None,'content_length_hdr':cl,'body_len':len(body),'field_names':list(flat.keys()),'has_x':'x' in flat,'has_n':'n' in flat,'len_n':len(flat.get('n','')) if 'n' in flat else None,'len_x':len(flat.get('x','')) if 'x' in flat else None,'anomalies':[] if not anomaly else [anomaly], 'body_preview': body[:120].decode('latin1','ignore')}
        if ('x' in flat) and ('n' in flat): rec['anomalies'].append('both_x_and_n')
        if ('x' not in flat) and ('n' not in flat): rec['anomalies'].append('neither_x_n')
        if 'x' in flat:
            x=flat['x']
            if len(x)%2: rec['anomalies'].append('x_odd_length')
            try:
                raw=binascii.unhexlify(x)
                bmp_path=os.path.join(OUTDIR, f'req_{req_idx}.bmp')
                with open(bmp_path,'wb') as wf: wf.write(raw)
                rec['x_info']=inspect_bmp(bmp_path, raw)
            except Exception as e:
                rec['anomalies'].append(f'x_hex_decode_error:{e}')
        rec['decoded_fields']=flat
        requests.append(rec)
        pos=body_end

with open(os.path.join(OUTDIR,'report2.json'),'w') as f: json.dump(requests,f,indent=2)
print('requests',len(requests))
print('with_x',sum(1 for r in requests if r['has_x']))
print('with_n',sum(1 for r in requests if r['has_n']))
for r in requests[:5]:
    print(r['req_idx'],r['frame_idx'],r['field_names'])

