from PIL import Image
from collections import deque
img=Image.open('/home/ctfplayer/ctf_files/artifacts/concat_all_x.bin').convert('RGB')
W,H=img.size
mask=[[0]*W for _ in range(H)]
for y in range(H):
    for x in range(W):
        r,g,b=img.getpixel((x,y))
        if r+g+b < 260: # dark-ish
            mask[y][x]=1
vis=[[False]*W for _ in range(H)]
comps=[]
for y in range(H):
    for x in range(W):
        if mask[y][x] and not vis[y][x]:
            q=deque([(x,y)]); vis[y][x]=True; pts=[]
            while q:
                cx,cy=q.popleft(); pts.append((cx,cy))
                for nx,ny in ((cx+1,cy),(cx-1,cy),(cx,cy+1),(cx,cy-1)):
                    if 0<=nx<W and 0<=ny<H and mask[ny][nx] and not vis[ny][nx]:
                        vis[ny][nx]=True; q.append((nx,ny))
            xs=[p[0] for p in pts]; ys=[p[1] for p in pts]
            comps.append((len(pts),min(xs),min(ys),max(xs),max(ys)))
comps=sorted(comps, reverse=True)
for c in comps[:50]:
    print(c)
